const token = $('Auth Input').item.json.token;

if (!token || typeof token !== 'string') {
  throw new Error('Missing bearer token');
}

const parts = token.split('.');
if (parts.length !== 3) {
  throw new Error('Malformed token');
}

// Base64url → base64 decode (no verification — only used to look up webhook_secret)
const base64 = parts[1].replace(/-/g, '+').replace(/_/g, '/');
const padded = base64 + '='.repeat((4 - base64.length % 4) % 4);

let payload;
try {
  payload = JSON.parse(Buffer.from(padded, 'base64').toString('utf8'));
} catch (e) {
  throw new Error('Malformed token payload');
}

if (!payload.client_id) {
  throw new Error('Token missing client_id claim');
}

return [{ json: { client_id: payload.client_id, jti: payload.jti || null, sid: payload.sid || null } }];

const result = $input.first().json;

if (!result || result.valid !== true) {
  throw new Error('Invalid request signature');
}

return [{ json: { hmac_valid: true } }];

const result = $input.first().json;

if (!result || result.valid !== true) {
  throw new Error('Invalid or expired token');
}

if (!result.user_id || !result.client_id) {
  throw new Error('Token missing required claims');
}

return [{
  json: {
    user_id: result.user_id,
    client_id: result.client_id,
    slug: result.slug,
    role: result.role,
    email: result.email
  }
}];

const claims = $('Check JWT Valid').first().json;
const userRow = $input.first().json;

if (!userRow || !userRow.name) {
  throw new Error('User not found or inactive');
}

return [{
  json: {
    user_id: claims.user_id,
    role: claims.role,
    client_id: claims.client_id,
    slug: claims.slug,
    name: userRow.name,
    email: claims.email,
    is_caiac_staff: userRow.is_caiac_staff === true,
    session_id: $('Decode JWT').item.json.sid || null,
    jti: $('Decode JWT').item.json.jti || null
  }
}];
